import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { 
  LogIn, UserPlus, ShieldCheck, FileText, CheckCircle, 
  X, LogOut, ArrowRight, Activity, Upload, Clock, Info, Plus, Search, MessageCircle, HelpCircle, LayoutDashboard, Users
} from 'lucide-react';

const Login = () => {
  // --- STATE ---
  const [view, setView] = useState('landing'); // landing, login, register, dashboard, admin-dashboard
  const [activeTab, setActiveTab] = useState('services'); 
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [showModal, setShowModal] = useState(false);
  const [showSupport, setShowSupport] = useState(false); 
  const [userRequests, setUserRequests] = useState([]); 
  const [isLoading, setIsLoading] = useState(false);

  // --- PERSISTENCE ---
  useEffect(() => {
    const token = localStorage.getItem('token');
    const role = localStorage.getItem('userRole');
    const userId = localStorage.getItem('userId');
    
    if (token) {
      setIsLoggedIn(true);
      if (role === 'admin') {
        setView('admin-dashboard');
      } else {
        setView('dashboard');
        if (userId) fetchRequests(userId);
      }
    }
  }, []);

  const fetchRequests = async (userId) => {
    try {
      const res = await axios.get(`http://localhost:5000/api/requests/user/${userId}`);
      setUserRequests(res.data);
    } catch (err) { console.log("Tracking error:", err); }
  };

  // --- LOGIN LOGIC WITH ROLE REDIRECTION ---
  const handleAuth = async (e) => {
    e.preventDefault();
    setIsLoading(true);
    const mode = view === 'register' ? 'register' : 'login';
    try {
      const res = await axios.post(`http://localhost:5000/api/auth/${mode}`, formData);
      if (mode === 'login') {
        localStorage.setItem('token', res.data.token);
        localStorage.setItem('userId', res.data.user._id);
        localStorage.setItem('userName', res.data.user.name);
        localStorage.setItem('userRole', res.data.user.role); // SAVE THE ROLE

        setIsLoggedIn(true);
        
        // REDIRECT BASED ON ROLE
        if (res.data.user.role === 'admin') {
          setView('admin-dashboard');
        } else {
          setView('dashboard');
        }
      } else {
        alert("Account Created! Please Sign In.");
        setView('login');
      }
    } catch (err) { alert("Authentication Failed"); }
    setIsLoading(false);
  };

  const handleCredentialSubmit = async (e) => {
    e.preventDefault();
    const requestBody = {
      userId: localStorage.getItem('userId'),
      userName: localStorage.getItem('userName'),
      type: e.target[0].value,
      licenseNumber: e.target[1].value,
    };
    try {
      const res = await axios.post('http://localhost:5000/api/requests/submit', requestBody);
      setUserRequests([res.data.request, ...userRequests]);
      setShowModal(false);
      alert("✅ Request Submitted!");
      setActiveTab('tracking'); 
    } catch (err) { alert("Submission Failed."); }
  };

  // --- REUSABLE SUPPORT MODAL ---
  const SupportModal = () => (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md flex items-center justify-center p-4 z-[200]">
      <div className="bg-white w-full max-w-md rounded-[3rem] shadow-2xl p-10 animate-in zoom-in duration-200">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-2xl font-black text-slate-900 flex items-center gap-2"><HelpCircle className="text-blue-600"/> Help Center</h2>
          <button onClick={() => setShowSupport(false)}><X className="text-slate-300 hover:text-slate-600"/></button>
        </div>
        <form onSubmit={(e) => { e.preventDefault(); alert("Ticket Sent!"); setShowSupport(false); }} className="space-y-4">
          <select className="w-full p-4 bg-slate-50 rounded-2xl border-none font-bold"><option>Login Issue</option><option>Verification Issue</option></select>
          <textarea placeholder="Describe issue..." className="w-full p-4 bg-slate-50 rounded-2xl h-32 outline-none" required></textarea>
          <button className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black">Send Ticket</button>
        </form>
      </div>
    </div>
  );

  // ==========================================
  // VIEW 1: LANDING PAGE
  // ==========================================
  if (view === 'landing') {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6">
        <div className="text-center mb-12 animate-in fade-in duration-1000">
           <div className="inline-block bg-blue-600 p-4 rounded-3xl mb-4 text-white shadow-xl shadow-blue-200"><ShieldCheck size={48} /></div>
           <h1 className="text-5xl font-black text-slate-900 tracking-tight italic uppercase">QUAD SOLUTIONS</h1>
           <p className="text-slate-500 font-medium">Professional Credentialing Portal</p>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 max-w-4xl w-full">
          <div onClick={() => setView('register')} className="bg-white p-10 rounded-[3rem] shadow-xl border-2 border-transparent hover:border-blue-600 cursor-pointer transition group">
             <div className="w-16 h-16 bg-blue-50 rounded-2xl flex items-center justify-center mb-6 text-blue-600 group-hover:scale-110 transition"><UserPlus size={32} /></div>
             <h2 className="text-2xl font-black text-slate-800 mb-2">New Providers</h2>
             <div className="flex items-center text-blue-600 font-bold group-hover:gap-2 transition-all">Get Started <ArrowRight size={20} className="ml-2" /></div>
          </div>
          <div onClick={() => setView('login')} className="bg-slate-900 p-10 rounded-[3rem] shadow-xl border-2 border-transparent hover:border-blue-400 cursor-pointer transition group text-white">
             <div className="w-16 h-16 bg-white/10 rounded-2xl flex items-center justify-center mb-6 text-blue-400 group-hover:scale-110 transition"><LogIn size={32} /></div>
             <h2 className="text-2xl font-black mb-2">Existing Clients</h2>
             <div className="flex items-center text-blue-400 font-bold group-hover:gap-2 transition-all">Sign In <ArrowRight size={20} className="ml-2" /></div>
          </div>
        </div>
        <button onClick={() => setShowSupport(true)} className="mt-12 text-slate-400 font-bold hover:text-blue-600 transition">Contact Support</button>
        {showSupport && <SupportModal />}
      </div>
    );
  }

  // ==========================================
  // VIEW 2: LOGIN / REGISTER FORMS
  // ==========================================
  if (view === 'login' || view === 'register') {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-6">
        <div className="w-full max-w-md bg-white p-10 rounded-[3rem] shadow-2xl relative">
          <button onClick={() => setView('landing')} className="absolute top-8 right-8 text-slate-300 hover:text-slate-600 font-bold">Back</button>
          <h2 className="text-4xl font-black mb-8 text-slate-900">{view === 'login' ? 'Login' : 'Register'}</h2>
          <form onSubmit={handleAuth} className="space-y-4">
            {view === 'register' && (
              <input type="text" placeholder="Full Name" className="w-full p-4 bg-slate-50 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500" onChange={(e) => setFormData({...formData, name: e.target.value})} required />
            )}
            <input type="email" placeholder="Email" className="w-full p-4 bg-slate-50 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500" onChange={(e) => setFormData({...formData, email: e.target.value})} required />
            <input type="password" placeholder="Password" className="w-full p-4 bg-slate-50 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500" onChange={(e) => setFormData({...formData, password: e.target.value})} required />
            <button className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black text-lg hover:bg-blue-700 transition">Continue</button>
            <p onClick={() => setView(view === 'login' ? 'register' : 'login')} className="text-center text-slate-400 font-bold cursor-pointer mt-4 italic underline underline-offset-4">Switch to {view === 'login' ? 'Register' : 'Login'}</p>
          </form>
          <button onClick={() => setShowSupport(true)} className="w-full mt-6 text-slate-300 font-bold text-xs hover:text-blue-600 transition uppercase tracking-widest">Login Issues? Contact Support</button>
        </div>
        {showSupport && <SupportModal />}
      </div>
    );
  }

  // ==========================================
  // VIEW 3: SECURE ADMIN DASHBOARD
  // ==========================================
     // ==========================================
  // VIEW 3: SECURE ADMIN DASHBOARD
  // ==========================================
  if (view === 'admin-dashboard') {
    return (
      <div className="min-h-screen bg-slate-900 text-white flex flex-col font-sans">
        <nav className="p-6 border-b border-slate-800 flex justify-between items-center bg-slate-950">
          <div className="flex items-center gap-3">
            <LayoutDashboard className="text-blue-400" />
            <h1 className="text-xl font-black tracking-widest text-blue-400 uppercase">Admin Control Panel</h1>
          </div>
          <button onClick={() => {localStorage.clear(); window.location.reload();}} className="bg-red-600/20 text-red-500 px-6 py-2 rounded-xl font-black hover:bg-red-600 hover:text-white transition">Secure Logout</button>
        </nav>

        <main className="p-10 max-w-7xl mx-auto w-full">
           {/* SECTION 1: STATISTICS */}
           <h2 className="text-3xl font-black mb-8 flex items-center gap-2"><Users /> System Overview</h2>
           <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
              <div className="bg-slate-800/50 p-8 rounded-[2rem] border border-slate-700">
                 <p className="text-slate-500 font-bold text-xs uppercase mb-1">Total Providers</p>
                 <h4 className="text-4xl font-black">24</h4>
              </div>
              <div className="bg-slate-800/50 p-8 rounded-[2rem] border border-slate-700 border-l-4 border-l-yellow-500">
                 <p className="text-slate-500 font-bold text-xs uppercase mb-1">Pending Documents</p>
                 <h4 className="text-4xl font-black text-yellow-500">{userRequests.length}</h4>
              </div>
              <div className="bg-slate-800/50 p-8 rounded-[2rem] border border-slate-700 border-l-4 border-l-green-500">
                 <p className="text-slate-500 font-bold text-xs uppercase mb-1">Approved today</p>
                 <h4 className="text-4xl font-black text-green-500">02</h4>
              </div>
           </div>
           
           {/* SECTION 2: DOCUMENT MANAGEMENT TABLE */}
           <div className="mt-16">
              <div className="flex justify-between items-end mb-8">
                <div>
                  <h2 className="text-2xl font-black text-white flex items-center gap-2">
                    <FileText className="text-blue-400"/> Manage Uploaded Documents
                  </h2>
                  <p className="text-slate-500 text-sm italic">Review and verify provider credentials below.</p>
                </div>
                <div className="text-slate-400 font-bold text-xs uppercase bg-slate-800 px-4 py-2 rounded-xl border border-slate-700 flex items-center gap-2">
                  <Search size={14}/> Filter: All Status
                </div>
              </div>

              <div className="bg-slate-800/40 rounded-[3rem] border border-slate-800 overflow-hidden shadow-2xl">
                <table className="w-full text-left">
                  <thead className="bg-slate-950/50 text-slate-500 text-[10px] font-black uppercase tracking-widest border-b border-slate-800">
                    <tr>
                      <th className="p-8">Provider Name</th>
                      <th className="p-8">Credential Type</th>
                      <th className="p-8">License ID</th>
                      <th className="p-8 text-center">Document</th>
                      <th className="p-8">Action</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-800/50">
                    {/* SIMULATED ROW FOR DR. JANE (Matches the table style) */}
                    <tr className="hover:bg-slate-800/60 transition group">
                      <td className="p-8">
                        <div className="flex items-center gap-3">
                          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center font-black">JS</div>
                          <span className="font-bold">Dr. Jane Smith</span>
                        </div>
                      </td>
                      <td className="p-8 text-slate-400">Medical License</td>
                      <td className="p-8 font-mono text-sm text-blue-400">#LIC-99021</td>
                      <td className="p-8 text-center">
                        <div className="w-12 h-12 bg-slate-900 rounded-xl mx-auto border border-slate-700 flex items-center justify-center text-slate-500 group-hover:text-blue-400 transition cursor-pointer">
                          <Upload size={18}/>
                        </div>
                      </td>
                      <td className="p-8">
                        <button className="bg-blue-600 text-white px-6 py-2 rounded-xl text-xs font-black hover:bg-blue-500 shadow-xl shadow-blue-600/10 transition">Approve</button>
                      </td>
                    </tr>

                    {/* DYNAMIC DATA FROM USERS (When they submit) */}
                    {userRequests.map((req) => (
                      <tr key={req._id} className="hover:bg-slate-800/60 transition group border-t border-slate-800/50">
                        <td className="p-8">
                          <div className="flex items-center gap-3">
                            <div className="w-10 h-10 bg-slate-700 rounded-xl flex items-center justify-center font-black">{req.userName.charAt(0)}</div>
                            <span className="font-bold">{req.userName}</span>
                          </div>
                        </td>
                        <td className="p-8 text-slate-400">{req.type}</td>
                        <td className="p-8 font-mono text-sm text-blue-400">#{req.licenseNumber}</td>
                        <td className="p-8 text-center">
                          <div title="Click to open image" className="w-12 h-12 bg-slate-900 rounded-xl mx-auto border border-slate-700 flex items-center justify-center text-slate-500 group-hover:text-blue-400 transition cursor-pointer">
                            <FileText size={18}/>
                          </div>
                        </td>
                        <td className="p-8">
                          <span className="text-yellow-500 bg-yellow-500/10 px-4 py-2 rounded-xl text-[10px] font-black uppercase">Pending</span>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
           </div>
        </main>
      </div>
    );
  }

  // ==========================================
  // VIEW 4: NORMAL USER DASHBOARD
  // ==========================================
  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <nav className="bg-white shadow-sm p-4 sticky top-0 z-50 border-b">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
          <h1 className="text-xl font-black text-blue-600 italic">QUAD SOLUTIONS</h1>
          <div className="flex gap-4 items-center">
             <button onClick={() => setActiveTab('services')} className={`px-4 py-2 rounded-xl text-sm font-bold ${activeTab === 'services' ? 'bg-blue-600 text-white' : 'text-slate-400'}`}>Services</button>
             <button onClick={() => setActiveTab('tracking')} className={`px-4 py-2 rounded-xl text-sm font-bold ${activeTab === 'tracking' ? 'bg-blue-600 text-white' : 'text-slate-400'}`}>My Status</button>
             <button onClick={() => setShowSupport(true)} title="Contact Support" className="p-2 text-slate-400 hover:text-blue-600 transition"><HelpCircle size={24}/></button>
             <button onClick={() => {localStorage.clear(); window.location.reload();}} className="text-red-500 font-bold px-2"><LogOut size={20}/></button>
          </div>
        </div>
      </nav>

      <main className="p-6 md:p-10 max-w-5xl mx-auto w-full">
        {activeTab === 'services' ? (
          <section className="animate-in fade-in duration-500">
             <h2 className="text-3xl font-black text-slate-900 mb-8">Service Catalog</h2>
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {['Medical License Renewal', 'Insurance Enrollment', 'DEA Certification'].map((item, idx) => (
                  <div key={idx} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 hover:shadow-xl transition duration-300">
                    <div className="w-12 h-12 bg-blue-50 rounded-xl flex items-center justify-center mb-4 text-blue-600"><FileText/></div>
                    <h3 className="text-xl font-bold mb-2">{item}</h3>
                    <button onClick={() => setShowModal(true)} className="w-full bg-slate-900 text-white py-3 rounded-xl font-bold mt-4 hover:bg-blue-600 transition">Apply Now</button>
                  </div>
                ))}
             </div>
          </section>
        ) : (
          <section className="animate-in fade-in duration-500">
             <h2 className="text-3xl font-black text-slate-900 mb-8">Tracking History</h2>
             <div className="space-y-6">
                {userRequests.length === 0 ? (
                  <div className="bg-white p-20 rounded-[3rem] text-center border-2 border-dashed border-slate-200 text-slate-300">No applications yet.</div>
                ) : (
                  userRequests.map((req, idx) => (
                    <div key={req._id} className="bg-white rounded-[2.5rem] shadow-sm border border-slate-100 p-8 flex justify-between items-center hover:shadow-md transition">
                       <div className="flex items-center gap-6">
                          <div className="w-16 h-16 bg-blue-50 rounded-2xl flex items-center justify-center text-blue-600 font-black text-xl">0{idx+1}</div>
                          <div><h3 className="text-xl font-black text-slate-800">{req.type}</h3><p className="text-slate-400 font-bold text-sm">ID: {req.licenseNumber}</p></div>
                       </div>
                       <span className={`px-4 py-2 rounded-xl text-xs font-black uppercase ${req.status === 'Approved' ? 'bg-green-100 text-green-600' : 'bg-blue-100 text-blue-600'}`}>
                          {req.status}
                       </span>
                    </div>
                  ))
                )}
             </div>
          </section>
        )}
      </main>

      {/* MODALS */}
      {showModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md flex items-center justify-center p-4 z-[100]">
          <div className="bg-white w-full max-w-md rounded-[3rem] shadow-2xl p-10 animate-in zoom-in duration-200">
            <h2 className="text-2xl font-black mb-6 text-blue-600">Start Submission</h2>
            <form onSubmit={handleCredentialSubmit} className="space-y-4">
              <select className="w-full p-4 bg-slate-50 rounded-2xl border-none font-bold text-slate-700 outline-none"><option>Medical License</option><option>Insurance Enrollment</option></select>
              <input type="text" placeholder="License / NPI Number" className="w-full p-4 bg-slate-50 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500" required />
              <button className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black shadow-xl shadow-blue-100 hover:bg-blue-700 transition">Confirm & Submit</button>
              <button onClick={() => setShowModal(false)} type="button" className="w-full text-slate-400 font-bold text-sm">Cancel</button>
            </form>
          </div>
        </div>
      )}
      {showSupport && <SupportModal />}
    </div>
  );
};

export default Login;
